### 2. Create a `Views/Settings/SettingsRootView.swift`

A settings hub that links to all sub-settings screens:

```swift
import SwiftUI

/// SettingsRootView is the main settings screen.
/// From here, users can navigate to configure:
/// - Endpoint (RTMP server URL, stream key, authentication)
/// - Video & Audio (resolution, bitrate, frame rate, audio settings)
/// - General (camera, orientation, battery, recording, about)
struct SettingsRootView: View {
    var body: some View {
        NavigationView {
            List {
                Section("Streaming") {
                    NavigationLink(destination: EndpointSettingsView()) {
                        Label("Endpoint", systemImage: "antenna.radiowaves.left.and.right")
                    }
                }

                Section("Quality") {
                    NavigationLink(destination: VideoAudioSettingsView()) {
                        Label("Video & Audio", systemImage: "video.fill")
                    }
                }

                Section("App") {
                    NavigationLink(destination: GeneralSettingsView()) {
                        Label("General", systemImage: "gearshape.fill")
                    }
                }
            }
            .navigationTitle("Settings")
        }
    }
}
```

